  id: string;
  title: string;
  content: string;
  createdAt: Date;
};

const posts: Post[] = [];

export function getPosts(): Post[] {
  // Return a copy sorted newest-first
  return [...posts].sort(
    (a, b) => b.createdAt.getTime() - a.createdAt.getTime()
  );
}

