{"file_path":"/home/user/workspace/lib/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { createPost } from '@/lib/data';

export async function createPostAction(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !title.trim() || !content || !content.trim()) {
    throw new Error('Title and content are required.');
  }

  createPost({ title: title.trim(), content: content.trim() });

  // Invalidate the 'posts' cache tag so the next fetch tagged with 'posts'
  // is a cache miss and fetches fresh data.
  revalidateTag('posts');

  // Redirect to the posts list — this triggers a full server navigation,
  // so there is no risk of the router cache serving stale content.
  redirect('/posts');
}
"}

