import { revalidateTag, revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import { createPost } from '@/lib/data';

export async function createPostAction(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !title.trim() || !content || !content.trim()) {
    throw new Error('Title and content are required.');
  }

  createPost({ title: title.trim(), content: content.trim() });

  // 1. Purge the Data Cache entries tagged 'posts' so the next fetch
  //    with { next: { tags: ['posts'] } } is a cache miss.
  revalidateTag('posts');

  // 2. Purge the Full Route Cache for /posts so the next request
  //    triggers a fresh server render (rather than serving a stale
  //    pre-rendered page while revalidating in the background).
  revalidatePath('/posts');

  // Redirect triggers a full navigation — the browser fetches /posts
  // fresh from the server, which now has neither a stale route cache
  // nor stale data cache entries.
  redirect('/posts');
}
"}

