import { updateTag, revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import { createPost } from '@/lib/data';

export async function createPostAction(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !title.trim() || !content || !content.trim()) {
    throw new Error('Title and content are required.');
  }

  createPost({ title: title.trim(), content: content.trim() });

  // 1. updateTag('posts') invalidates the Data Cache entries tagged
  //    with 'posts' — this is the Server Action-specific API with
  //    read-your-own-writes semantics (the mutation sees its own
  //    changes immediately on the next fetch).
  updateTag('posts');

  // 2. revalidatePath('/posts') purges the Full Route Cache for
  //    /posts, guaranteeing the next request triggers a fresh
  //    server-side render rather than serving a stale cached page
  //    while revalidating in the background.
  revalidatePath('/posts');

  // 3. Redirect navigates the browser to /posts.  Combined with the
  //    two invalidations above, this ensures the page loads with
  //    completely fresh data — no stale route cache, no stale data
  //    cache, and no client-side router cache.
  redirect('/posts');
}
"}

