{"file_path":"/home/user/workspace/app/posts/page.tsx","content":"import { cacheTag } from 'next/cache';
import { createPostAction } from '@/lib/actions';
import type { Post } from '@/lib/data';

export default async function PostsPage() {
  // Tag this component's cached data with 'posts' so a Server Action
  // can invalidate it on-demand via updateTag('posts').
  cacheTag('posts');

  const res = await fetch(
    `${process.env.NEXT_PUBLIC_BASE_URL ?? 'http://localhost:3000'}/api/posts`,
  );
  const posts: Post[] = await res.json();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>

      {/* ── Create form ── */}
      <form
        action={createPostAction}
        style={{
          display: 'flex',
          flexDirection: 'column',
          gap: '0.5rem',
          marginBottom: '2rem',
          padding: '1rem',
          border: '1px solid #ccc',
          borderRadius: 8,
        }}
      >
        <input
          name="title"
          placeholder="Post title"
          required
          style={{ padding: '0.5rem', fontSize: '1rem' }}
        />
        <textarea
          name="content"
          placeholder="Post content"
          required
          rows={4}
          style={{ padding: '0.5rem', fontSize: '1rem' }}
        />
        <button
          type="submit"
          style={{
            padding: '0.5rem 1rem',
            fontSize: '1rem',
            cursor: 'pointer',
          }}
        >
          Create Post
        </button>
      </form>

      {/* ── Posts list ── */}
      <h2>All Posts</h2>
      {posts.length === 0 ? (
        <p>No posts yet. Create one above!</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li
              key={post.id}
              style={{
                padding: '1rem',
                marginBottom: '0.75rem',
                border: '1px solid #eee',
                borderRadius: 6,
              }}
            >
              <h3 style={{ margin: '0 0 0.25rem' }}>{post.title}</h3>
              <p style={{ margin: '0 0 0.25rem', color: '#555' }}>
                {post.content}
              </p>
              <small style={{ color: '#999' }}>
                {new Date(post.createdAt).toLocaleString()}
              </small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}
"}

